    #[test]
    fn resolves_svg_embedded_asset_refs_safely() {
        assert_eq!(
            super::resolve_svg_embedded_asset_ref(
                "figures/plots/vector.svg",
                "../shared/pixel.png"
            ),
            Some("figures/shared/pixel.png".to_string())
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref(
                "figures/plots/vector.svg",
                "./nested/pixel.png?cache=1#frag"
            ),
            Some("figures/plots/nested/pixel.png".to_string())
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref(
                "figures/vector.svg",
                "nested/a%20b%26c.png?cache=1#frag"
            ),
            Some("figures/nested/a b&c.png".to_string())
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref(
                "figures/vector.svg",
                "nested/a%3Fb%23c.png?cache=1#frag"
            ),
            Some("figures/nested/a?b#c.png".to_string())
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref("figures/vector.svg", "nested/a%zz%2.png"),
            Some("figures/nested/a%zz%2.png".to_string())
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref("figures/vector.svg", "nested/%E2%82%AC.png"),
            Some("figures/nested/\u{20ac}.png".to_string())
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref("figures/vector.svg", "nested/a%2Fb.png"),
            Some("figures/nested/a%2Fb.png".to_string())
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref("figures/vector.svg", "nested/a%00b.png"),
            Some("figures/nested/a%00b.png".to_string())
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref("figures/vector.svg", "nested/a%0Ab.png"),
            Some("figures/nested/a%0Ab.png".to_string())
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref("figures/vector.svg", "nested/a%7Fb.png"),
            Some("figures/nested/a%7Fb.png".to_string())
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref("figures/vector.svg", "nested/a\nb.png"),
            None
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref("figures/vector.svg", "nested/a\tb.png"),
            None
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref("figures/vector.svg", r"nested\pixel.png"),
            None
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref("figures/vector.svg", r"..\outside.png"),
            None
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref("figures/vector.svg", "nested/\0pixel.png"),
            None
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref("figures/vector.svg", "nested/../pixel.png"),
            Some("figures/pixel.png".to_string())
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref("vector.svg", "nested/pixel.png"),
            Some("nested/pixel.png".to_string())
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref("figures/vector.svg", "#stamp"),
            None
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref("figures/vector.svg", "/nested/pixel.png"),
            None
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref(
                "figures/vector.svg",
                "https://example.com/pixel.png"
            ),
            None
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref(
                "figures/vector.svg",
                "https%3A%2F%2Fexample.com/pixel.png"
            ),
            None
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref("figures/vector.svg", "C%3A/pixel.png"),
            None
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref("figures/vector.svg", "%ff%3A/pixel.png"),
            None
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref("figures/vector.svg", "../outside.png"),
            Some("outside.png".to_string())
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref("figures/vector.svg", "../../outside.png"),
            None
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref("figures/vector.svg", "%2e%2e/outside.png"),
            Some("outside.png".to_string())
        );
        assert_eq!(
            super::resolve_svg_embedded_asset_ref(
                "figures/vector.svg",
                "%2e%2e/%2e%2e/outside.png"
            ),
            None
        );
    }

